const queries = [
  // === GOOGLE ALERTS SIMULATION (High Priority) ===
  // Fresh news signals — companies seeking AI/software partners
  { q: '"looking for" OR "seeking" "AI development company" OR "software agency" OR "ML company" OR "automation agency" 2025', platform: 'google_alerts', priority: 'high' },
  { q: '"outsource" OR "outsourcing" "AI" OR "machine learning" OR "automation" OR "software development" "company" OR "startup" 2025', platform: 'google_alerts', priority: 'high' },
  { q: '"just raised" OR "we raised" OR "closes funding" "AI" OR "SaaS" OR "automation" "build" OR "hire" OR "expand" 2025', platform: 'google_alerts', priority: 'high' },
  { q: '"series a" OR "seed round" OR "pre-seed" "AI" OR "automation" OR "SaaS" "build" OR "engineering" OR "development" 2025 -site:crunchbase.com -site:techcrunch.com', platform: 'google_alerts', priority: 'high' },
  { q: '"request for proposal" OR "RFP" OR "looking for vendor" "AI" OR "machine learning" OR "automation" OR "software" private 2025', platform: 'google_alerts', priority: 'high' },
  { q: '"need a" OR "looking for a" "software development company" OR "AI company" OR "tech agency" OR "development partner" 2025', platform: 'google_alerts', priority: 'high' },

  // === MEDIUM — Low Priority ===
  { q: 'site:medium.com/swlh "AI" OR "automation" OR "SaaS" "build" OR "startup" OR "founder" 2025', platform: 'medium', priority: 'low' },
  { q: 'site:medium.com/better-programming "AI" OR "machine learning" OR "automation" "build" OR "company" OR "startup" 2025', platform: 'medium', priority: 'low' },
  { q: 'site:medium.com "AI development" OR "custom software" OR "automation agency" "startup" OR "founder" OR "company" 2025', platform: 'medium', priority: 'low' },
  { q: 'site:medium.com "outsource software" OR "hire development team" OR "find AI agency" OR "software partner" 2025', platform: 'medium', priority: 'low' },

  // === SUBSTACK — Low Priority ===
  { q: 'site:substack.com "AI" OR "SaaS" OR "automation" "startup" OR "founder" "build" OR "hire" OR "partner" 2025', platform: 'substack', priority: 'low' },
  { q: 'site:substack.com "software development" OR "AI development" OR "machine learning" "company" OR "agency" OR "outsource" 2025', platform: 'substack', priority: 'low' },

  // === TELEGRAM (publicly indexed channels) — Low Priority ===
  { q: 'site:t.me "AI" OR "automation" OR "software" OR "SaaS" "looking for" OR "hire" OR "build" OR "outsource"', platform: 'telegram', priority: 'low' },
  { q: 'site:t.me "startup" OR "founder" "AI development" OR "software agency" OR "tech partner" OR "build MVP"', platform: 'telegram', priority: 'low' },

  // === INDEED CONTRACT POSTINGS — Low Priority ===
  { q: 'site:indeed.com "contract" "AI" OR "machine learning" OR "automation" OR "software development" "startup" OR "funded" OR "series a"', platform: 'indeed', priority: 'low' },
  { q: 'site:indeed.com "contract" OR "freelance" "ML engineer" OR "AI engineer" OR "automation engineer" OR "data engineer" "startup" OR "seed"', platform: 'indeed', priority: 'low' },
  { q: 'site:indeed.com "contract" "AI development" OR "computer vision" OR "LLM" OR "RAG" OR "AI agent" OR "data pipeline"', platform: 'indeed', priority: 'low' }
];
return queries.map(q => ({ json: q }));

const skipKeywords = [
  'for hire', 'i am available', 'hire me', 'my portfolio', 'i offer',
  'available for work', 'seeking employment', 'looking for work',
  'logo design', 'seo services', 'social media manager', 'content writer',
  'virtual assistant', 'data entry', 'graphic designer',
  'how to become a developer', 'learn to code', 'best programming language',
  'government contract', 'federal rfp', 'dod contract', 'state agency'
];

const platformMap = {
  'medium.com': 'medium',
  'substack.com': 'substack',
  't.me': 'telegram',
  'telegram.me': 'telegram',
  'indeed.com': 'indeed',
  'techcrunch.com': 'google_alerts',
  'venturebeat.com': 'google_alerts',
  'businessinsider.com': 'google_alerts',
  'forbes.com': 'google_alerts'
};

const priorityMap = {
  'google_alerts': 'high',
  'medium': 'low',
  'substack': 'low',
  'telegram': 'low',
  'indeed': 'low'
};

const budgetPatterns = [
  /([\$€£][\d,]+(?:,\d{3})*(?:k)?(?:\s[-–]\s*[\$€£]?[\d,]+(?:k)?)?(?:\s*(?:USD|EUR|GBP))?)/i,
  /(\d+[kK]\s*[-–]\s*\d+[kK])/,
  /budget[:\s]+([\$€£][\d,k.]+[\s\w-]*)/i,
  /raised\s+([\$€£][\d,.]+ ?(?:million|M|billion|B)?)/i
];

const results = [];
const seenInRun = new Set();

for (const item of $input.all()) {
  const data = item.json;
  if (!data || data.error) continue;

  const searchQ = data.search_parameters?.q || '';
  const organicResults = data.organic_results || [];

  // Infer platform from query
  let platform = 'google_alerts';
  if (searchQ.includes('medium.com')) platform = 'medium';
  else if (searchQ.includes('substack.com')) platform = 'substack';
  else if (searchQ.includes('t.me') || searchQ.includes('telegram')) platform = 'telegram';
  else if (searchQ.includes('indeed.com')) platform = 'indeed';

  for (const r of organicResults) {
    const link = r.link || '';
    if (!link) continue;

    // Detect actual platform from URL
    let actualPlatform = platform;
    for (const [domain, pname] of Object.entries(platformMap)) {
      if (link.includes(domain)) { actualPlatform = pname; break; }
    }

    // Skip Indeed full-time positions (keep contract only)
    if (actualPlatform === 'indeed') {
      const snippet = (r.snippet || '').toLowerCase();
      const title = (r.title || '').toLowerCase();
      if (!snippet.includes('contract') && !snippet.includes('freelance') && !title.includes('contract') && !title.includes('freelance')) continue;
    }

    const id = actualPlatform + '_' + link.replace(/[^a-z0-9]/gi, '').slice(-70);
    if (seenInRun.has(id)) continue;
    seenInRun.add(id);

    const title   = String(r.title   || '').substring(0, 500);
    const snippet = String(r.snippet || '').replace(/<[^>]*>/g, '').substring(0, 3000);
    if (!title) continue;

    const fullText = (title + ' ' + snippet).toLowerCase();
    if (skipKeywords.some(kw => fullText.includes(kw))) continue;

    let budget_text = '';
    for (const pat of budgetPatterns) {
      const m = (snippet + ' ' + title).match(pat);
      if (m) { budget_text = (m[1] || m[0]).trim().substring(0, 80); break; }
    }

    results.push({ json: {
      title,
      description: snippet,
      source: actualPlatform,
      source_url: link,
      source_id: id,
      posted_at: (() => { try { const d = r.date ? new Date(r.date) : null; return (d && !isNaN(d)) ? d.toISOString() : new Date().toISOString(); } catch(e) { return new Date().toISOString(); } })(),
      author: '',
      subreddit: actualPlatform,
      upvotes: 0,
      num_comments: 0,
      flair_text: priorityMap[actualPlatform] || 'low',
      budget_text,
      platform: actualPlatform
    }});
  }
}

if (results.length === 0) return [{ json: { _empty: true, platform: 'misc' } }];
return results.slice(0, 30);

const post = $input.item.json;
if (post._empty || post._noData) return { json: post };

const apiKey = $env.GOOGLE_AI_API_KEY;

const SYSTEM_PROMPT = `You are a senior business development analyst for ScaleBuild AI (CEO: Ujjwal Roy, ex-Intel/IBM/Micron), a custom AI/ML software development company.

ScaleBuild BUILDS: AI/ML models, computer vision, enterprise automation, custom software, data pipelines.

These leads come from MIXED SIGNALS — Google Alerts (news/web), Medium articles, Substack newsletters, Telegram channels, and Indeed contract postings. Each source has different signal quality:

PLATFORM CONTEXT:
- google_alerts: Real-time news — company funding announcements, companies seeking AI/software partners. HIGH signal.
- indeed (contract): Contract job postings from companies that can't hire fast enough — prime outsourcing signal. HIGH signal.
- medium: Startup/tech articles. Signal only if founder describing a build need or pain point.
- substack: Newsletters by founders/operators. Signal if discussing a software problem or seeking partners.
- telegram: Public startup/founder channels. Variable signal — good if discussing build needs.

IDEAL LEAD: Company just funded seeking to build fast, or posting contract work, or publicly discussing a tech problem ScaleBuild AI can solve.

HARD EXCLUSIONS — Score overall_score 0.0 immediately, do not process:
- Lead is from India or an Indian company (location: India, .in domain, Indian city/company name context) → 0.0
- Lead is requesting to build a SaaS subscription product (we do NOT build SaaS products) → 0.0  
- Budget is clearly under $10,000 OR budget_score would be below 0.3 → 0.0
- Individual freelancer or [For Hire] ad → 0.0

SCORE 4 DIMENSIONS (0.0-1.0):
1. relevance_score: 1.0=Indeed contract for AI/ML/automation OR news about company seeking AI partner | 0.9=funding news + build signal | 0.8=founder describing specific AI/software need | 0.7=startup content with tech build context | 0.5=general startup/tech content | 0.2=article/opinion no buyer signal | 0.0=irrelevant
2. budget_score: 1.0=Indeed contract $50K+ OR Series A/B raise | 0.8=$10-50K contract OR seed raise | 0.7=funded startup unknown contract size | 0.6=bootstrapped with revenue | 0.5=unknown startup context | 0.3=small signal | 0.1=no signal
3. urgency_score: 1.0=active Indeed contract posting this week | 0.8=funding announcement + build signal this month | 0.6=recent article discussing active need | 0.4=exploring options | 0.2=older content | 0.1=evergreen article no urgency
4. win_probability: 0.9=contract posting for AI/ML/automation agency | 0.8=company explicitly seeking dev partner | 0.7=funded startup needs to build fast | 0.5=medium fit, needs nurturing | 0.3=indirect signal | 0.1=no fit

BUDGET ESTIMATION (ALWAYS fill estimated_budget_text, never null):
- Indeed contract AI/ML → "$15K-$100K (contract scope)"
- Series A/B company → "$50K-$500K (post-funding build)"
- Seed stage → "$15K-$75K (seed build)"
- Medium/Substack founder → "$10K-$50K (estimated from context)"
- Telegram group signal → "$10K-$75K (startup scope)"
- Unknown → "$15K-$75K (estimated)"

COMPANY EXTRACTION: Extract company name, founder name, website from snippet/title/URL. Never invent. Return null if not found.`;

const prompt = SYSTEM_PROMPT + `\n\nScore this mixed-signal lead. Return ONLY a single valid JSON object:\n{"relevance_score":0.0,"budget_score":0.0,"urgency_score":0.0,"win_probability":0.0,"summary":"2-4 sentence summary: what the signal is, who it's from, what they need, and why ScaleBuild AI fits or doesn't","industry":"FinTech/HealthTech/SaaS/AI/Manufacturing/eCommerce/General","tags":["tag1","tag2"],"reasoning":"Explain each score — why relevance, why budget, why urgency, why win probability. Clear recommendation: pursue or skip and best outreach angle.","estimated_budget_text":"$X-$Y (reason)","tech_stack":[],"company_name":null,"lead_founder_name":null,"lead_website":null}\n\nTitle: ${post.title}\nPlatform: ${post.source} (Priority: ${post.flair_text})\nDescription: ${(post.description||'').substring(0, 1200)}${post.budget_text ? '\nBudget Signal: ' + post.budget_text : ''}`;

const body = {
  contents: [{ parts: [{ text: prompt }] }],
  generationConfig: { maxOutputTokens: 100000, temperature: 0.2, responseMimeType: 'application/json' }
};

let s = null;
try {
  const respRaw = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=' + apiKey,
    body
  });
  const resp = typeof respRaw === 'string' ? JSON.parse(respRaw) : respRaw;
  const raw = resp?.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const cleaned = raw.replace(/```json[\s\S]*?```|```/g, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) s = JSON.parse(match[0]);
} catch(e) {}

if (!s) s = {
  relevance_score:0.3, budget_score:0.4, urgency_score:0.3, win_probability:0.3,
  summary:'Parse error - using defaults', industry:'General', tags:[], reasoning:'Could not parse Gemini response',
  estimated_budget_text:'$15K-$75K (estimated)', tech_stack:[],
  company_name:null, lead_founder_name:null, lead_website:null
};

const overall = Math.round(((s.relevance_score*0.35)+(s.budget_score*0.30)+(s.urgency_score*0.15)+(s.win_probability*0.20))*100)/100;
const alert_tier = overall>=0.85?'instant':overall>=0.70?'digest':overall>=0.30?'dashboard':'discard';

return { json: {
  source_id: post.source_id, title: post.title, description: post.description,
  source: post.source, source_url: post.source_url, posted_at: post.posted_at,
  author: post.author||'', subreddit: post.subreddit||post.source||'',
  upvotes: 0, num_comments: 0, flair_text: post.flair_text||'misc',
  relevance_score: s.relevance_score, budget_score: s.budget_score,
  urgency_score: s.urgency_score, win_probability: s.win_probability,
  overall_score: overall, ai_summary: s.summary, industry: s.industry,
  ai_tags: s.tags||[], ai_reasoning: s.reasoning,
  estimated_budget_text: s.estimated_budget_text||'',
  budget_mentioned: post.budget_text || s.estimated_budget_text || '',
  tech_stack: s.tech_stack||[], company_name: s.company_name||null,
  lead_founder: s.lead_founder_name||null, lead_company: s.company_name||null,
  lead_website: s.lead_website||null, lead_contact: null,
  lead_score: Math.round(overall*10),
  alert_tier, discovered_at: new Date().toISOString(), status:'new',
  location: s.location||null, deadline_text: null,
  outreach_draft: '',
  hunter_name:'', hunter_email:'', hunter_title:'', hunter_company:'',
  hunter_all_emails:'', hunter_all_names:'', hunter_all_titles:''
}};

const hunterResp = $input.item.json;
const original = $('Check - Has Lead Info').item.json;
const data = hunterResp?.data || {};
const emails = data.emails || [];
const org = data.organization || original.lead_company || '';

if (emails.length === 0) {
  return [{ json: { ...original, hunter_name: '', hunter_email: '', hunter_title: '', hunter_company: org, hunter_all_emails: '', hunter_all_names: '', hunter_all_titles: '' } }];
}

const priority = ['ceo','founder','co-founder','cto','owner','president','vp','director'];
const best = emails.find(e => priority.some(t => (e.position||'').toLowerCase().includes(t))) || emails[0];

const allEmails  = emails.map(e => e.value || '').filter(Boolean).join(', ');
const allNames   = emails.map(e => (e.first_name||e.last_name) ? `${e.first_name||''} ${e.last_name||''}`.trim() : '').filter(Boolean).join(', ');
const allTitles  = emails.map(e => e.position || '').filter(Boolean).join(', ');

return [{ json: {
  ...original,
  hunter_name:       best.first_name || best.last_name ? `${best.first_name||''} ${best.last_name||''}`.trim() : '',
  hunter_email:      best.value || '',
  hunter_title:      best.position || '',
  hunter_company:    org,
  hunter_all_emails: allEmails,
  hunter_all_names:  allNames,
  hunter_all_titles: allTitles
}}];

const seen = new Map();
for (const item of $input.all()) {
  const id = item.json.source_id;
  if (!id) continue;
  if (!seen.has(id)) {
    seen.set(id, item.json);
  } else {
    if (item.json.hunter_email && !seen.get(id).hunter_email) {
      seen.set(id, item.json);
    }
  }
}
return [...seen.values()]
  .sort((a, b) => (b.overall_score||0) - (a.overall_score||0))
  .map(json => ({ json }));
